VALUES
  ('locality-d0d1b9a2-moex-00514', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '依我國審計準則公報第56號「會計估計與相關揭露之查核」之規範，查核人員於查核財務報 表時，對會計估計（包括公允價值會計估計）與相關揭露負有責任。下列敘述何者錯誤？', '["查核人員如判斷某一會計估計存有顯著風險，應瞭解與該風險攸關之內部控制，尤其是控 制作業", "若管理階層將作會計估計之基礎，由依市價評估改為依模型評估，查核人員應依經濟情況 評估管理階層對市場之假設是否合理", "查核人員應要求管理階層（如適當時，亦包括治理單位）對其認為作會計估計時所採用之 重大假設係屬合理一事，列入書面聲明", "查核人員對管理階層所採用假設之評估，僅基於查核當時可取得之資訊，執行與該等假設 有關之查核程序，係以對該等假設表示意見為目的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "0e5dce46d5c3", "answer_pdf_sha1": "6df25b623a35", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00515', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '依審計準則公報第47號之規定，查核規劃包括查核策略及查核計畫，下列何者非查核計畫應 包括事項？', '["確定查核案件之報導目的，以規劃查核之時間及須溝通之內容與方式", "擬執行風險評估程序之性質、時間及範圍", "對個別項目聲明所規劃進一步查核程序之性質、時間及範圍", "為使案件之執行遵循審計準則公報而規劃之其他必要查核程序"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "0e5dce46d5c3", "answer_pdf_sha1": "6df25b623a35", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00516', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '依據審計準則公報規定，查核人員於財務報表查核案件有關對內部控制之瞭解，下列何者正確？', '["小規模企業因內部控制較不完善，查核人員以證實程序為主要查核策略，因此無須對內部 控制組成要素進行瞭解", "如查核人員不擬信賴與顯著風險有關之控制，則無須對其進行瞭解", "查核人員對與查核攸關控制作業之瞭解應評估其設計是否有效性，並確認是否付諸實行", "查核人員對控制作業瞭解最有效之方法係直接執行控制測試"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "0e5dce46d5c3", "answer_pdf_sha1": "6df25b623a35", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00517', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-0e802df0', 'sub-locality-d0d1b9a2-05', NULL, 'single_choice', '根據審計準則公報第62號「與受查者治理單位之溝通」，下列何者不是查核人員須與治理單 位溝通之事項？', '["管理階層編製財務報表之責任", "查核人員查核財務報表之責任", "所規劃之查核範圍及時間", "查核之重大發現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "0e5dce46d5c3", "answer_pdf_sha1": "6df25b623a35", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
